SELECT bs.state AS state, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.electricity.total.energy_consumption..kwh" * bs.weight) AS "electricity.total.energy_consumption..kwh__baseline", sum(up."out.electricity.total.energy_consumption..kwh" * bs.weight) AS "electricity.total.energy_consumption..kwh__upgrade", sum((coalesce(bs."out.electricity.total.energy_consumption..kwh", 0) - coalesce(up."out.electricity.total.energy_consumption..kwh", 0)) * bs.weight) AS "electricity.total.energy_consumption..kwh__savings" FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up ON bs.bldg_id = up.bldg_id AND bs."in.nhgis_tract_gisjoin" = up."in.nhgis_tract_gisjoin" AND bs.state = up.state AND bs.upgrade = 0 AND up.upgrade = 1 AND up.applicability = true WHERE bs.applicability = true AND bs.upgrade = 0 AND bs.bldg_id = 51037 GROUP BY 1 ORDER BY 1